mapper.select:
SELECT format(SUM(price)*0.8,2) FROM app_rescue_indent
 WHERE user_b_id = #{id}
 AND (state = 3 or state = 5)
 AND to_days(create_time) = to_days(now());

SELECT id,merchants_name merchantsName,type merchantsType,lng,lat,merchants_phone phoneNumber,state,business_start businessStart,business_end businessEnd,address,announcement
FROM app_b_user
WHERE id = #{userBId}

SELECT SUM(price) FROM(
SELECT SUM(amount)*0.9 price FROM app_clean_indet
WHERE user_b_id = #{userBId} AND (indent_state = 3 or indent_state = 6) AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth} AND contract_flag  <>  1
UNION ALL
SELECT SUM(price)*0.8 price FROM app_rescue_indent
WHERE user_b_id = #{userBId} AND  state = 6 AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
UNION ALL
SELECT SUM(price)*0.8 price FROM app_spray_paint_indent
WHERE user_b_id = #{userBId} AND (state = 3 or state = 6) AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
UNION ALL
SELECT SUM(price)*0.8 price FROM app_year_check_indent
WHERE user_b_id = #{userBId} AND  state = 6 AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
) t;

SELECT SUM(amount) FROM(
 SELECT partner_trade_no id,concat('余额提现')operationName,amount amount,concat(1)type,date_format(create_time,'%Y-%m') operationMonth,create_time createTime
     FROM app_wx_cash_out_record  WHERE sources =2 and  user_id = #{userBId} AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
 UNION ALL
 SELECT id,concat('视频扣款')operationName,deduction amount,concat(3)type,date_format(create_time,'%Y-%m')operationMonth,create_time createTime
     FROM app_push_bill WHERE user_id = #{userBId} AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
 UNION ALL
 SELECT id,concat('订单结算')operationName,fixloss_user amount,concat(4)type,date_format(creat_time,'%Y-%m')operationMonth,creat_time createTime
     FROM app_indent WHERE  user_b_id = #{userBId} AND state = 6 AND DATE_FORMAT(creat_time,'%Y-%m') = #{operationMonth}
     ) t

SELECT huanxin_username huanxinUserName,huanxin_password huanxinPassword,
                unread_message unreadMessage,save_time saveTime
 FROM app_up_merchants WHERE id = #{member}
